// Created: 2026-03-29

/**
 * Unit tests for setup-maintenance hook
 * Tests: mode detection, log rotation, stale lock cleanup,
 * session cleanup, health validation, version migration, marker edge cases.
 */

import { describe, test, expect, beforeEach, afterEach, vi } from 'vitest';
import { mkdirSync, writeFileSync, mkdtempSync, rmSync, statSync, chmodSync, utimesSync, readFileSync, readdirSync, existsSync } from 'node:fs';
import { join } from 'node:path';
import os from 'node:os';
import { mockCommonBasic } from '../fixtures/mock-common.js';

vi.mock('../../lib/common.js', () => mockCommonBasic());

vi.mock('../../lib/paths.js', () => ({
  getHomeDir: vi.fn(() => '/mock/home'),
  getTempDir: vi.fn(() => '/mock/tmp'),
}));

vi.mock('../../lib/agent-teams.js', () => ({
  isAgentTeamsActive: vi.fn(() => false),
}));

vi.mock('../../lib/atomic-write.js', () => ({
  atomicWriteSync: vi.fn((filePath: string, content: string) => {
    require('node:fs').writeFileSync(filePath, content);
  }),
}));

import { setupMaintenance } from '../../setup/setup-maintenance.js';
import { getPluginRoot } from '../../lib/common.js';
import { getHomeDir, getTempDir } from '../../lib/paths.js';
import { isAgentTeamsActive } from '../../lib/agent-teams.js';
import type { HookInput } from '../../types.js';
import { createTestContext } from '../fixtures/test-context.js';

const mockGetPluginRoot = vi.mocked(getPluginRoot);
const mockGetHomeDir = vi.mocked(getHomeDir);
const mockGetTempDir = vi.mocked(getTempDir);
const mockIsAgentTeamsActive = vi.mocked(isAgentTeamsActive);

let tmpDir: string;

function input(overrides: Partial<HookInput> = {}): HookInput {
  return { tool_name: '', session_id: 'test-maint', project_dir: tmpDir, tool_input: {}, ...overrides };
}

function writeMarker(data: Record<string, unknown>): void {
  writeFileSync(join(tmpDir, '.setup-complete'), JSON.stringify(data));
}

function readMarker(): Record<string, unknown> {
  return JSON.parse(readFileSync(join(tmpDir, '.setup-complete'), 'utf-8'));
}

let testCtx: ReturnType<typeof createTestContext>;
beforeEach(() => {
  testCtx = createTestContext();
  vi.clearAllMocks();
  tmpDir = mkdtempSync(join(os.tmpdir(), 'setup-maint-test-'));
  mockGetPluginRoot.mockReturnValue(tmpDir);
  mockGetHomeDir.mockReturnValue(join(tmpDir, 'home'));
  mockGetTempDir.mockReturnValue(join(tmpDir, 'tmp'));
  process.argv = ['node', 'test'];
});

afterEach(() => {
  try { rmSync(tmpDir, { recursive: true, force: true }); } catch { /* ignore */ }
});

describe('setup-maintenance', () => {
  // ── Mode detection ──────────────────────────────────────────────────
  describe('mode detection', () => {
    test('auto mode with no marker still continues', () => {
      // Note: tasksCompleted is module-level and accumulates across calls,
      // so we only assert continue:true (not suppressOutput).
      const result = setupMaintenance(input(), testCtx);
      expect(result.continue).toBe(true);
    });

    test('force mode runs daily and weekly tasks', () => {
      process.argv = ['node', 'test', '--force'];
      mkdirSync(join(tmpDir, '.claude', 'logs'), { recursive: true });
      writeMarker({ version: '4.25.0', last_maintenance: null });
      const result = setupMaintenance(input(), testCtx);
      expect(result.continue).toBe(true);
    });

    test('migrate mode only runs version migration', () => {
      process.argv = ['node', 'test', '--migrate'];
      writeMarker({ version: '3.0.0' });
      const result = setupMaintenance(input(), testCtx);
      expect(result.continue).toBe(true);
      expect(readMarker().version).toBe('4.25.0');
    });

    test('background mode returns silent success even when tasks run', () => {
      process.argv = ['node', 'test', '--background'];
      const oldDate = new Date(Date.now() - 25 * 3600_000).toISOString();
      writeMarker({ last_maintenance: oldDate, version: '4.25.0' });
      mkdirSync(join(tmpDir, '.claude', 'logs'), { recursive: true });
      expect(setupMaintenance(input())).toEqual({ continue: true, suppressOutput: true });
    });
  });

  // ── Auto scheduling ─────────────────────────────────────────────────
  describe('auto scheduling', () => {
    test('skips tasks when last maintenance was recent', () => {
      writeMarker({ last_maintenance: new Date().toISOString(), version: '4.25.0' });
      // No new tasks scheduled, but tasksCompleted is module-level so may have prior entries
      expect(setupMaintenance(input()).continue).toBe(true);
    });

    test('runs daily tasks when >24h since last maintenance', () => {
      writeMarker({ last_maintenance: new Date(Date.now() - 25 * 3600_000).toISOString(), version: '4.25.0' });
      mkdirSync(join(tmpDir, '.claude', 'logs'), { recursive: true });
      const result = setupMaintenance(input(), testCtx);
      expect(result.continue).toBe(true);
    });

    test('runs weekly tasks when >168h since last maintenance', () => {
      writeMarker({ last_maintenance: new Date(Date.now() - 170 * 3600_000).toISOString(), version: '4.25.0' });
      mkdirSync(join(tmpDir, '.claude', 'logs'), { recursive: true });
      mkdirSync(join(tmpDir, 'hooks'), { recursive: true });
      const result = setupMaintenance(input(), testCtx);
      expect(result.continue).toBe(true);
    });
  });

  // ── Log rotation ────────────────────────────────────────────────────
  describe('log rotation', () => {
    test('rotates log files larger than 200KB', () => {
      process.argv = ['node', 'test', '--force'];
      const logsDir = join(tmpDir, '.claude', 'logs');
      mkdirSync(logsDir, { recursive: true });
      writeFileSync(join(logsDir, 'big.log'), 'x'.repeat(205_000));
      writeMarker({ version: '4.25.0' });
      setupMaintenance(input(), testCtx);
      expect(existsSync(join(logsDir, 'big.log'))).toBe(false);
    });

    test('does not rotate small log files', () => {
      process.argv = ['node', 'test', '--force'];
      const logsDir = join(tmpDir, '.claude', 'logs');
      mkdirSync(logsDir, { recursive: true });
      writeFileSync(join(logsDir, 'small.log'), 'small');
      writeMarker({ version: '4.25.0' });
      setupMaintenance(input(), testCtx);
      expect(existsSync(join(logsDir, 'small.log'))).toBe(true);
    });

    test('cleans old rotated logs keeping last 5', () => {
      process.argv = ['node', 'test', '--force'];
      const logsDir = join(tmpDir, '.claude', 'logs');
      mkdirSync(logsDir, { recursive: true });
      for (let i = 0; i < 7; i++) writeFileSync(join(logsDir, `a.log.old.2026-01-0${i + 1}`), 'old');
      writeMarker({ version: '4.25.0' });
      setupMaintenance(input(), testCtx);
      const remaining = readdirSync(logsDir).filter((f: string) => f.includes('.log.old.'));
      expect(remaining.length).toBeLessThanOrEqual(5);
    });
  });

  // ── Session cleanup ─────────────────────────────────────────────────
  describe('session cleanup', () => {
    test('archives sessions older than 7 days', () => {
      process.argv = ['node', 'test', '--force'];
      const sessionDir = join(tmpDir, '.claude', 'context', 'sessions');
      mkdirSync(sessionDir, { recursive: true });
      const old = join(sessionDir, 'old-session');
      mkdirSync(old);
      const eightDaysAgo = new Date(Date.now() - 8 * 86_400_000);
      utimesSync(old, eightDaysAgo, eightDaysAgo);
      writeMarker({ version: '4.25.0' });
      setupMaintenance(input(), testCtx);
      expect(existsSync(join(tmpDir, '.claude', 'context', 'archive', 'old-session'))).toBe(true);
      expect(existsSync(old)).toBe(false);
    });

    test('does not archive recent sessions', () => {
      process.argv = ['node', 'test', '--force'];
      const sessionDir = join(tmpDir, '.claude', 'context', 'sessions');
      mkdirSync(sessionDir, { recursive: true });
      const recent = join(sessionDir, 'recent');
      mkdirSync(recent);
      writeMarker({ version: '4.25.0' });
      setupMaintenance(input(), testCtx);
      expect(existsSync(recent)).toBe(true);
    });
  });

  // ── Stale lock cleanup ──────────────────────────────────────────────
  describe('stale lock cleanup', () => {
    test('removes .lock files older than 24h', () => {
      process.argv = ['node', 'test', '--force'];
      const lockFile = join(tmpDir, 'old.lock');
      writeFileSync(lockFile, 'locked');
      utimesSync(lockFile, new Date(Date.now() - 48 * 3600_000), new Date(Date.now() - 48 * 3600_000));
      writeMarker({ version: '4.25.0' });
      setupMaintenance(input(), testCtx);
      expect(existsSync(lockFile)).toBe(false);
    });

    test('preserves recent .lock files', () => {
      process.argv = ['node', 'test', '--force'];
      const lockFile = join(tmpDir, 'recent.lock');
      writeFileSync(lockFile, 'locked');
      writeMarker({ version: '4.25.0' });
      setupMaintenance(input(), testCtx);
      expect(existsSync(lockFile)).toBe(true);
    });

    test('skips coordination DB when Agent Teams is active', () => {
      // --force triggers daily tasks which include taskStaleLockCleanup
      process.argv = ['node', 'test', '--force'];
      mockIsAgentTeamsActive.mockReturnValue(true);
      writeMarker({ version: '4.25.0' });
      // Create coordination dir so the path exists (triggering the check)
      mkdirSync(join(tmpDir, '.claude', 'coordination'), { recursive: true });
      writeFileSync(join(tmpDir, '.claude', 'coordination', '.claude.db'), '');
      setupMaintenance(input(), testCtx);
      expect(mockIsAgentTeamsActive).toHaveBeenCalled();
    });
  });

  // ── Health validation ───────────────────────────────────────────────
  describe('health validation', () => {
    test('fixes non-executable shell scripts', () => {
      process.argv = ['node', 'test', '--force'];
      writeMarker({ last_maintenance: new Date(Date.now() - 170 * 3600_000).toISOString(), version: '4.25.0' });
      const hooksDir = join(tmpDir, 'hooks');
      mkdirSync(hooksDir, { recursive: true });
      const sh = join(hooksDir, 'hook.sh');
      writeFileSync(sh, '#!/bin/bash');
      chmodSync(sh, 0o644);
      setupMaintenance(input(), testCtx);
      expect(statSync(sh).mode & 0o111).toBeTruthy();
    });

    test('handles invalid config.json gracefully', () => {
      process.argv = ['node', 'test', '--force'];
      writeMarker({ last_maintenance: new Date(Date.now() - 170 * 3600_000).toISOString(), version: '4.25.0' });
      const cfgDir = join(tmpDir, '.claude', 'defaults');
      mkdirSync(cfgDir, { recursive: true });
      writeFileSync(join(cfgDir, 'config.json'), 'NOT JSON{{{');
      expect(setupMaintenance(input()).continue).toBe(true);
    });
  });

  // ── Version migration ──────────────────────────────────────────────
  describe('version migration', () => {
    test('updates marker version on mismatch', () => {
      process.argv = ['node', 'test', '--migrate'];
      writeMarker({ version: '3.0.0' });
      setupMaintenance(input(), testCtx);
      expect(readMarker().version).toBe('4.25.0');
    });

    test('skips when version matches', () => {
      process.argv = ['node', 'test', '--migrate'];
      writeMarker({ version: '4.25.0' });
      const result = setupMaintenance(input(), testCtx);
      expect(result.continue).toBe(true);
      // Version should remain unchanged
      expect(readMarker().version).toBe('4.25.0');
    });

    test('skips when no version in marker', () => {
      process.argv = ['node', 'test', '--migrate'];
      writeMarker({});
      const result = setupMaintenance(input(), testCtx);
      expect(result.continue).toBe(true);
      // No version key should be added
      expect(readMarker().version).toBeUndefined();
    });
  });

  // ── Edge cases ──────────────────────────────────────────────────────
  describe('edge cases', () => {
    test('handles missing marker file', () => {
      process.argv = ['node', 'test', '--force'];
      expect(setupMaintenance(input()).continue).toBe(true);
    });

    test('handles corrupted marker file', () => {
      writeFileSync(join(tmpDir, '.setup-complete'), 'NOT JSON');
      expect(setupMaintenance(input()).continue).toBe(true);
    });

    test('uses input.project_dir when provided', () => {
      const customDir = join(tmpDir, 'custom');
      mkdirSync(customDir, { recursive: true });
      expect(setupMaintenance(input({ project_dir: customDir })).continue).toBe(true);
    });
  });
});
